(function(){'use strict';var galleryData;var searchTimeout=null;var DEBOUNCE_MS=150;function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function highlight(text,query){if(!query)return esc(text);var safe=esc(text);var safeQuery=query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');try{var re=new RegExp('('+safeQuery+')','gi');return safe.replace(re,'<mark>$1</mark>');}catch(e){return safe;}}
function matches(dataset,query){if(!query)return true;var q=query.toLowerCase();if(dataset.name.toLowerCase().indexOf(q)!==-1)return true;if(dataset.description&&dataset.description.toLowerCase().indexOf(q)!==-1)return true;if(dataset.keywords){var kws=Array.isArray(dataset.keywords)?dataset.keywords:String(dataset.keywords).split(',');for(var i=0;i<kws.length;i++){if(String(kws[i]).toLowerCase().indexOf(q)!==-1)return true;}}
return false;}
function conformsToLabel(conformsTo){if(!conformsTo)return'';var m=String(conformsTo).match(/(\d+\.\d+(?:\.\d+)?)$/);return m?m[1]:conformsTo;}
function renderTopBar(totalCount){return('<header class="topbar">'+
'<a class="topbar-brand" href="#">'+
'<span class="logo">🥐</span>'+
'<span class="brand-text">Croissant</span>'+
'</a>'+
'<div class="topbar-divider"></div>'+
'<span class="topbar-title">Dataset Gallery</span>'+
'<div class="search-wrap" id="search-wrap">'+
'<span class="search-icon">'+_searchIcon()+'</span>'+
'<input class="search-input" id="search-input" type="search"'+
' placeholder="Search datasets by name, description, keywords…"'+
' autocomplete="off" autocorrect="off" spellcheck="false">'+
'<span class="search-kbd" aria-hidden="true">⌘K</span>'+
'<button class="search-clear" id="search-clear" title="Clear search" aria-label="Clear search">✕</button>'+
'</div>'+
'<span class="topbar-count" id="topbar-count">'+totalCount+' datasets</span>'+
'</header>');}
function _searchIcon(){return'<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>';}
function renderSidebar(versions){var sections=versions.map(function(v){var label=v.label;var items=v.datasets.map(function(d){return'<li><a href="#card-'+esc(d.slug)+'" data-slug="'+esc(d.slug)+'">'+esc(d.name)+'</a></li>';}).join('');return('<div class="sidebar-section open" data-version="'+esc(label)+'">'+
'<button class="sidebar-section-toggle">'+
'<svg class="sidebar-chevron" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="9 18 15 12 9 6"/></svg>'+
' Croissant '+esc(label)+
'<span class="sidebar-section-count">'+v.datasets.length+'</span>'+
'</button>'+
'<ul class="sidebar-dataset-list">'+items+'</ul>'+
'</div>');}).join('');return('<nav class="gallery-sidebar">'+
'<div class="sidebar-inner">'+sections+'</div>'+
'</nav>');}
function renderCard(dataset,query){var name=highlight(dataset.name,query);var desc=highlight(dataset.description||'',query);var versionPill=dataset.version?'<span class="card-version">v'+esc(dataset.version)+'</span>':'';var chips='';if(typeof dataset.num_resources==='number'){chips+='<span class="card-chip">📦 '+dataset.num_resources+' resource'+(dataset.num_resources===1?'':'s')+'</span>';}
if(typeof dataset.num_record_sets==='number'){chips+='<span class="card-chip">📋 '+dataset.num_record_sets+' record set'+(dataset.num_record_sets===1?'':'s')+'</span>';}
var license=dataset.license?'<span class="card-license">⚖️ '+esc(dataset.license)+'</span>':'';return('<a class="gallery-card" id="card-'+esc(dataset.slug)+'" href="'+esc(dataset.path)+'">'+
'<div class="card-title-row">'+
'<span class="card-name">'+name+'</span>'+
versionPill+
'</div>'+
'<div class="card-description">'+desc+'</div>'+
'<div class="card-footer">'+
chips+
license+
'</div>'+
'</a>');}
function renderSection(v,query){var cards=v.datasets.map(function(d){return renderCard(d,query);}).join('');var conformsToLink=v.conformsTo?'<a href="'+esc(v.conformsTo)+'" target="_blank" rel="noopener">'+esc(v.conformsTo)+'</a>':'';return('<section class="gallery-section" data-version="'+esc(v.label)+'">'+
'<div class="gallery-section-header">'+
'<h2>Croissant '+esc(v.label)+'</h2>'+
'<span class="gallery-section-badge" id="badge-'+esc(v.label)+'">'+v.datasets.length+'</span>'+
(conformsToLink?'<span class="gallery-section-conformsto">'+conformsToLink+'</span>':'')+
'</div>'+
'<div class="gallery-grid" id="grid-'+esc(v.label)+'">'+cards+'</div>'+
'</section>');}
function renderReadme(){if(!galleryData.readme_intro)return'';var intro=galleryData.readme_intro;var rest=galleryData.readme_rest;var html='<div class="gallery-readme" style="background:var(--color-surface);border:1px solid var(--color-border);border-radius:var(--radius);padding:20px;margin-bottom:24px;box-shadow:var(--shadow-sm);">';html+='<p class="readme-intro" style="font-size:0.95rem;color:var(--color-text);">'+esc(intro)+'</p>';if(rest){html+='<button class="readme-toggle" id="readme-toggle" style="background:none;border:none;color:var(--color-primary);cursor:pointer;font-size:0.85rem;font-weight:600;padding:4px 0;margin-top:8px;">More...</button>';html+='<div class="readme-rest" id="readme-rest" style="display:none;margin-top:12px;font-size:0.88rem;color:var(--color-text-secondary);">'+marked.parse(rest)+'</div>';}
html+='</div>';return html;}
function renderApp(){var versions=galleryData.versions;var totalCount=versions.reduce(function(n,v){return n+v.datasets.length;},0);var sections=versions.map(function(v){return renderSection(v,'');}).join('');return(renderTopBar(totalCount)+
'<div class="gallery-layout">'+
renderSidebar(versions)+
'<main class="gallery-main" id="gallery-main">'+
renderReadme()+
sections+
'<div class="gallery-empty" id="gallery-empty" style="display:none">'+
'<div class="empty-icon">🔍</div>'+
'<h3>No datasets found</h3>'+
'<p>Try a different search term.</p>'+
'</div>'+
'<div class="gallery-footer">Generated by 🥐 <strong>Croissant Visualizer</strong> · <a href="https://mlcommons.org/croissant" target="_blank">mlcommons.org/croissant</a></div>'+
'</main>'+
'</div>');}
function applyFilter(query){var versions=galleryData.versions;var totalVisible=0;versions.forEach(function(v){var sectionEl=document.querySelector('.gallery-section[data-version="'+v.label+'"]');var sidebarSection=document.querySelector('.sidebar-section[data-version="'+v.label+'"]');var badge=document.getElementById('badge-'+v.label);var visibleInSection=0;v.datasets.forEach(function(d){var cardEl=document.getElementById('card-'+d.slug);var sidebarLink=sidebarSection?sidebarSection.querySelector('a[data-slug="'+d.slug+'"]'):null;var visible=matches(d,query);if(cardEl){if(visible){cardEl.classList.remove('hidden');var nameEl=cardEl.querySelector('.card-name');var descEl=cardEl.querySelector('.card-description');if(nameEl)nameEl.innerHTML=highlight(d.name,query);if(descEl)descEl.innerHTML=highlight(d.description||'',query);visibleInSection++;totalVisible++;}else{cardEl.classList.add('hidden');var nameEl=cardEl.querySelector('.card-name');var descEl=cardEl.querySelector('.card-description');if(nameEl)nameEl.innerHTML=esc(d.name);if(descEl)descEl.innerHTML=esc(d.description||'');}}
if(sidebarLink){sidebarLink.parentElement.classList.toggle('hidden',!visible);}});if(sectionEl)sectionEl.classList.toggle('hidden',visibleInSection===0);if(badge)badge.textContent=visibleInSection;});var emptyEl=document.getElementById('gallery-empty');if(emptyEl)emptyEl.style.display=totalVisible===0?'block':'none';var countEl=document.getElementById('topbar-count');if(countEl){var total=versions.reduce(function(n,v){return n+v.datasets.length;},0);countEl.textContent=query?totalVisible+' of '+total+' datasets':total+' datasets';}
var wrap=document.getElementById('search-wrap');if(wrap)wrap.classList.toggle('has-query',!!query);}
function attachEvents(){var input=document.getElementById('search-input');var clearBtn=document.getElementById('search-clear');input.addEventListener('input',function(){var q=input.value.trim();clearTimeout(searchTimeout);searchTimeout=setTimeout(function(){applyFilter(q);},DEBOUNCE_MS);});clearBtn.addEventListener('click',function(){input.value='';applyFilter('');input.focus();});document.addEventListener('keydown',function(e){if((e.metaKey||e.ctrlKey)&&e.key==='k'){e.preventDefault();input.focus();input.select();}
if(e.key==='Escape'&&document.activeElement===input){input.blur();}});document.querySelectorAll('.sidebar-section-toggle').forEach(function(btn){btn.addEventListener('click',function(){var section=btn.closest('.sidebar-section');if(section)section.classList.toggle('open');});});document.querySelectorAll('.sidebar-dataset-list a').forEach(function(a){a.addEventListener('click',function(e){e.preventDefault();var slug=a.getAttribute('data-slug');var card=document.getElementById('card-'+slug);if(card){card.scrollIntoView({behavior:'smooth',block:'center'});card.style.outline='2px solid var(--color-primary)';setTimeout(function(){card.style.outline='';},1500);}});});var readmeToggle=document.getElementById('readme-toggle');if(readmeToggle){readmeToggle.addEventListener('click',function(){var rest=document.getElementById('readme-rest');if(rest){var isHidden=rest.style.display==='none';rest.style.display=isHidden?'block':'none';readmeToggle.textContent=isHidden?'Less...':'More...';}});}}
function init(){if(!window.__GALLERY_DATA__){document.getElementById('app').innerHTML='<p style="padding:2rem;color:#b91c1c">Error: gallery data not found.</p>';return;}
galleryData=window.__GALLERY_DATA__;document.getElementById('app').innerHTML=renderApp();document.title='Croissant Dataset Gallery';attachEvents();}
init();})();